using namespace std;

class UnionFind {
private:
    vector<int> parent;
public:
    UnionFind(int n) {
        parent.resize(n);
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        int fx = find(x);
        int fy = find(y);
        if (fx != fy) {
            parent[fy] = fx;
        }
    }
};

long long solve(vector<long long> nums, vector<vector<long long>> swaps) {
    int n = nums.size();
    UnionFind uf(n);

    for (const auto& swap : swaps) {
        int u = swap[0];
        int v = swap[1];
        uf.unite(u, v);
    }

    vector<vector<long long>> groups(n);
    for (int i = 0; i < n; ++i) {
        groups[uf.find(i)].push_back(nums[i]);
    }

    for (auto& group : groups) {
        sort(group.begin(), group.end(), greater<long long>());
    }

    vector<long long> new_nums(n);
    for (int i = 0; i < n; ++i) {
        int root = uf.find(i);
        if (!groups[root].empty()) {
            new_nums[i] = groups[root].back();
            groups[root].pop_back();
        }
    }

    long long res = 0;
    for (int i = 0; i < n; ++i) {
        if (i % 2 == 0) {
            res += new_nums[i];
        } else {
            res -= new_nums[i];
        }
    }

    return res;
}
